// In visitCall for intrinsic calls
Case(llvm::fshl):
  if (match(Arg1, m_Zero())) {
    // Check shift amount range
    if (isKnownNonNegative(Arg2) && isKnownLessThan(Arg2, BitWidth)) {
      replaceInstUsesWith(CI, Builder.CreateShl(Arg0, Arg2));
    }
  }
  break;
Case(llvm::fshr):
  if (match(Arg0, m_Zero())) {
    if (isKnownNonNegative(Arg2) && isKnownLessThan(Arg2, BitWidth)) {
      replaceInstUsesWith(CI, Builder.CreateLShr(Arg1, Arg2));
    }
  }
  break;

